sql:
SELECT label_format
FROM labeling_standards
WHERE standard_description LIKE '%beige%';

external_knowledge:
- "star performers" refers to the testers who have conducted numerous tests;
- "seeds planted" is a metaphor for the number of tests conducted by each tester;
- The ranking is based on the descending order of the number of tests.

sql:
SELECT equipment_type 
FROM equipment_classes 
WHERE class_id = 1;

SELECT COUNT(*) 
FROM compliance_records 
WHERE compliance_status = 'Non-Compliant';

SELECT compliance_status
FROM compliance_records
WHERE class_id = 1;

SELECT equipment_type, AVG(test_dc_volts) AS average_test_dc_volts
FROM equipment_classes
GROUP BY equipment_type;

